public class Shared {
    static int count = 0;

    static void increment() { count++; }

    public static void main(String[] args) {
        increment();
        increment();
        System.out.println(count);

        count = 0;
        for (int i = 0; i < 5; i++) increment();
        System.out.println(count);
    }
}
